import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { ReconciliationService } from '../services/reconciliation.service';
import { Account } from '../../../core/models/index';

@Component({
  selector: 'app-accounts',
  templateUrl: './accounts.component.html',
  styleUrls: ['./accounts.component.scss'],
})
export class AccountsComponent {
  query = '';
  accounts: Account[] = [];
  loading = false;
  error = '';

  constructor(
    private readonly reconciliationService: ReconciliationService,
    private readonly router: Router,
  ) {}

  search(): void {
    this.loading = true;
    this.error = '';
    this.accounts = [];

    this.reconciliationService.searchAccounts(this.query.trim()).subscribe({
      next: (result) => {
        this.accounts = result;
        this.loading = false;
      },
      error: (err: Error) => {
        this.error = err.message || 'No se pudieron buscar cuentas';
        this.loading = false;
      },
    });
  }

  openAccount(account: Account): void {
    this.router.navigate(['/accounts', account.id]);
  }
}
<div class="accounts-panel">
  <div class="search-header">
    <div>
      <h2>Buscar cuentas</h2>
      <p>Encuentra cuentas por nombre o ID y consulta sus detalles.</p>
    </div>
    <div class="search-actions">
      <input
        type="text"
        [(ngModel)]="query"
        placeholder="Ingrese término de búsqueda"
        (keyup.enter)="search()"
      />
      <button type="button" (click)="search()" [disabled]="loading">
        {{ loading ? 'Buscando...' : 'Buscar' }}
      </button>
    </div>
  </div>

  <div *ngIf="error" class="alert-error">{{ error }}</div>

  <div *ngIf="accounts.length > 0" class="accounts-list">
    <div class="account-row" *ngFor="let account of accounts" (click)="openAccount(account)">
      <div>
        <strong>{{ account.name }}</strong>
        <small>ID: {{ account.id }}</small>
      </div>
      <div class="account-values">
        <span>Saldo libro: {{ account.ledgerBalance | number:'1.0-2' }}</span>
        <span>Saldo sistema: {{ account.systemBalance | number:'1.0-2' }}</span>
      </div>
    </div>
  </div>

  <div *ngIf="!loading && accounts.length === 0" class="empty-state">
    Introduce un término y haz clic en buscar para ver cuentas.
  </div>
</div>
